parameters.jsCode:
const proyecto = $input.item.json.proyecto || "PVV";
const tipo = ($input.item.json.tipo_media || "amenidades").toLowerCase().trim();
const canal = ($input.item.json.canal || "whatsapp").toLowerCase().trim();

// URLs reales por proyecto y tipo de media.
// Dejar en null los que aún no tienen archivo listo.
const database = {
  "PVV": {
    "amenidades": "https://res.cloudinary.com/dif0pqsok/image/upload/v1763745364/amenidades_dble4k.png",
    "renders": null,
    "planos": null,
    "brochure": null
  },
  "PMAR": {
    "amenidades": null,
    "renders": null,
    "planos": null,
    "brochure": null
  },
  "PPO": {
    "amenidades": null,
    "renders": null,
    "planos": null,
    "brochure": null
  },
  "PPOL": {
    "amenidades": null,
    "renders": null,
    "planos": null,
    "brochure": null
  },
  "PSB": {
    "amenidades": null,
    "renders": null,
    "planos": null,
    "brochure": null
  }
};

const projectData = database[proyecto] || database["PVV"];
const url = projectData[tipo] || null;

const objectType = canal === 'whatsapp' ? 'text' : 'image';
const keyName = canal === 'whatsapp' ? 'text' : 'url';

return [{
  json: {
    manychat_id: $input.item.json.manychat_id,
    canal: canal,
    proyecto: proyecto,
    url: url,
    media_disponible: url !== null,
    objectType: objectType,
    keyName: keyName
  }
}];

